import React, { lazy, Suspense } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { HelmetProvider } from 'react-helmet-async';
import { Toaster } from 'react-hot-toast';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import ProtectedRoute from './components/ProtectedRoute';
import AdminRoute from './components/AdminRoute';
import RouteFallback from './components/RouteFallback';
import { CartProvider } from './context/CartContext';
import { AuthProvider } from './context/AuthContext';
import { WishlistProvider } from './context/WishlistContext';

const Home = lazy(() => import('./pages/Home'));
const Shop = lazy(() => import('./pages/Products'));
const ProductDetail = lazy(() => import('./pages/ProductDetail'));
const CategoryPage = lazy(() => import('./pages/CategoryPage'));
const LegacyShopRedirect = lazy(() => import('./pages/LegacyShopRedirect'));
const LegacyProductRedirect = lazy(() => import('./pages/LegacyProductRedirect'));
const Login = lazy(() => import('./pages/Login'));
const Register = lazy(() => import('./pages/Register'));
const ForgotPassword = lazy(() => import('./pages/auth/ForgotPassword'));
const ResetPassword = lazy(() => import('./pages/auth/ResetPassword'));
const VerifyEmail = lazy(() => import('./pages/auth/VerifyEmail'));
const Cart = lazy(() => import('./pages/Cart'));
const Checkout = lazy(() => import('./pages/Checkout'));
const OrderConfirmation = lazy(() => import('./pages/OrderConfirmation'));
const AccountLayout = lazy(() => import('./pages/account/AccountLayout'));
const AccountHome = lazy(() => import('./pages/account/AccountHome'));
const AccountOrdersPage = lazy(() => import('./pages/account/AccountOrdersPage'));
const AccountOrderDetailPage = lazy(() => import('./pages/account/AccountOrderDetailPage'));
const AccountProfilePage = lazy(() => import('./pages/account/AccountProfilePage'));
const AccountAddressesPage = lazy(() => import('./pages/account/AccountAddressesPage'));
const AccountWishlistPage = lazy(() => import('./pages/account/AccountWishlistPage'));
const Orders = lazy(() => import('./pages/Orders'));
const WishlistPage = lazy(() => import('./pages/WishlistPage'));
const NotFound = lazy(() => import('./pages/NotFound'));
const AdminLayout = lazy(() => import('./pages/admin/AdminLayout'));
const AdminPlaceholder = lazy(() => import('./pages/admin/AdminPlaceholder'));
const AdminProductEditPage = lazy(() => import('./pages/admin/AdminProductEditPage'));

function App() {
  return (
    <HelmetProvider>
      <AuthProvider>
        <WishlistProvider>
          <CartProvider>
            <Router>
              <div className="App">
                <Toaster position="top-right" toastOptions={{ duration: 3500 }} />
                <Navbar />
                <main className="main-content">
                  <Suspense fallback={<RouteFallback />}>
                    <Routes>
                      <Route path="/" element={<Home />} />
                      <Route path="/shop" element={<Shop />} />
                      <Route path="/shop/:slug" element={<ProductDetail />} />
                      <Route path="/category/:slug" element={<CategoryPage />} />

                      <Route path="/login" element={<Login />} />
                      <Route path="/register" element={<Register />} />
                      <Route path="/forgot-password" element={<ForgotPassword />} />
                      <Route path="/reset-password/:token" element={<ResetPassword />} />
                      <Route path="/verify-email/:token" element={<VerifyEmail />} />

                      <Route path="/products" element={<LegacyShopRedirect />} />
                      <Route path="/product/:slug" element={<LegacyProductRedirect />} />

                      <Route
                        path="/cart"
                        element={
                          <ProtectedRoute>
                            <Cart />
                          </ProtectedRoute>
                        }
                      />
                      <Route
                        path="/checkout"
                        element={
                          <ProtectedRoute>
                            <Checkout />
                          </ProtectedRoute>
                        }
                      />
                      <Route
                        path="/order-confirmation/:id"
                        element={
                          <ProtectedRoute>
                            <OrderConfirmation />
                          </ProtectedRoute>
                        }
                      />

                      <Route
                        path="/account"
                        element={
                          <ProtectedRoute>
                            <AccountLayout />
                          </ProtectedRoute>
                        }
                      >
                        <Route index element={<AccountHome />} />
                        <Route path="orders" element={<AccountOrdersPage />} />
                        <Route path="orders/:id" element={<AccountOrderDetailPage />} />
                        <Route path="profile" element={<AccountProfilePage />} />
                        <Route path="addresses" element={<AccountAddressesPage />} />
                        <Route path="wishlist" element={<AccountWishlistPage />} />
                      </Route>

                      <Route
                        path="/orders"
                        element={
                          <ProtectedRoute>
                            <Orders />
                          </ProtectedRoute>
                        }
                      />
                      <Route path="/wishlist" element={<WishlistPage />} />

                      <Route
                        path="/admin"
                        element={
                          <AdminRoute>
                            <AdminLayout />
                          </AdminRoute>
                        }
                      >
                        <Route index element={<AdminPlaceholder title="Dashboard" />} />
                        <Route path="products" element={<AdminPlaceholder title="Products" />} />
                        <Route
                          path="products/new"
                          element={<AdminPlaceholder title="New product" />}
                        />
                        <Route path="products/:id/edit" element={<AdminProductEditPage />} />
                        <Route path="orders" element={<AdminPlaceholder title="Orders" />} />
                        <Route
                          path="orders/:id"
                          element={<AdminPlaceholder title="Order detail" />}
                        />
                        <Route path="categories" element={<AdminPlaceholder title="Categories" />} />
                        <Route path="customers" element={<AdminPlaceholder title="Customers" />} />
                        <Route path="coupons" element={<AdminPlaceholder title="Coupons" />} />
                        <Route path="analytics" element={<AdminPlaceholder title="Analytics" />} />
                      </Route>

                      <Route path="*" element={<NotFound />} />
                    </Routes>
                  </Suspense>
                </main>
                <Footer />
              </div>
            </Router>
          </CartProvider>
        </WishlistProvider>
      </AuthProvider>
    </HelmetProvider>
  );
}

export default App;
